    s2 = lb.ref("s2", "( ( ( ( ( ( φ ∧ η ) ∧ ζ ) ∧ σ ) ∧ ρ ) ∧ μ ) → ( λ → κ ) )", s1, ref="adantl4r", note="adantl4r")
    res = lb.ref("res", "( ( ( ( ( ( ( φ ∧ η ) ∧ ζ ) ∧ σ ) ∧ ρ ) ∧ μ ) ∧ λ ) → κ )", s2, ref="imp", note="imp")
    return lb.build(res)

