def prove_pm3_33(sys: System) -> Proof:
    """Theorem *3.33 (Syll) of [WhiteheadRussell] p. 112.  (Contributed by NM,
    3-Jan-2005.)
    """
    lb = ProofBuilder(sys, "pm3.33")
    s1 = lb.ref("s1", "( ( φ → ψ ) → ( ( ψ → χ ) → ( φ → χ ) ) )", ref="imim1", note="imim1")
    res = lb.ref("res", "( ( ( φ → ψ ) ∧ ( ψ → χ ) ) → ( φ → χ ) )", s1, ref="imp", note="imp")
    return lb.build(res)

