def prove_impbida(sys: System) -> Proof:
    """Deduce an equivalence from two implications.  Variant of ~ impbid .
    (Contributed by NM, 17-Feb-2007.)
    """
    lb = ProofBuilder(sys, "impbida")
    h1 = lb.hyp("impbida.1", "( ( φ ∧ ψ ) → χ )")
    h2 = lb.hyp("impbida.2", "( ( φ ∧ χ ) → ψ )")
    s1 = lb.ref("s1", "( φ → ( ψ → χ ) )", h1, ref="ex", note="ex")
    s2 = lb.ref("s2", "( φ → ( χ → ψ ) )", h2, ref="ex", note="ex")
    res = lb.ref("res", "( φ → ( ψ ↔ χ ) )", s1, s2, ref="impbid", note="impbid")
    return lb.build(res)

def prove_pm5_21nd(sys: System) -> Proof:
    """Eliminate an antecedent implied by each side of a biconditional.
    Variant of ~ pm5.21ndd .  (Contributed by NM, 20-Nov-2005.)  (Proof
    shortened by Wolf Lammen, 4-Nov-2013.)
    """
    lb = ProofBuilder(sys, "pm5.21nd")
    h1 = lb.hyp("pm5.21nd.1", "( ( φ ∧ ψ ) → θ )")
    h2 = lb.hyp("pm5.21nd.2", "( ( φ ∧ χ ) → θ )")
    h3 = lb.hyp("pm5.21nd.3", "( θ → ( ψ ↔ χ ) )")
    s1 = lb.ref("s1", "( φ → ( ψ → θ ) )", h1, ref="ex", note="ex")
    s2 = lb.ref("s2", "( φ → ( χ → θ ) )", h2, ref="ex", note="ex")
    s3 = lb.ref("s3", "( φ → ( θ → ( ψ ↔ χ ) ) )", h3, ref="a1i", note="a1i")
    res = lb.ref("res", "( φ → ( ψ ↔ χ ) )", s1, s2, s3, ref="pm5.21ndd", note="pm5.21ndd")
    return lb.build(res)

def prove_pm3_35(sys: System) -> Proof:
    """Conjunctive detachment.  Theorem *3.35 of [WhiteheadRussell] p. 112.
    Variant of ~ pm2.27 .  (Contributed by NM, 14-Dec-2002.)
    """
    lb = ProofBuilder(sys, "pm3.35")
    s1 = lb.ref("s1", "( φ → ( ( φ → ψ ) → ψ ) )", ref="pm2.27", note="pm2.27")
    res = lb.ref("res", "( ( φ ∧ ( φ → ψ ) ) → ψ )", s1, ref="imp", note="imp")
    return lb.build(res)

def prove_pm5_74da(sys: System) -> Proof:
    """Distribution of implication over biconditional (deduction form).
    Variant of ~ pm5.74d .  (Contributed by NM, 4-May-2007.)
    """
    lb = ProofBuilder(sys, "pm5.74da")
    h1 = lb.hyp("pm5.74da.1", "( ( φ ∧ ψ ) → ( χ ↔ θ ) )")
    s1 = lb.ref("s1", "( φ → ( ψ → ( χ ↔ θ ) ) )", h1, ref="ex", note="ex")
    res = lb.ref("res", "( φ → ( ( ψ → χ ) ↔ ( ψ → θ ) ) )", s1, ref="pm5.74d", note="pm5.74d")
    return lb.build(res)

def prove_bitr(sys: System) -> Proof:
    """Theorem *4.22 of [WhiteheadRussell] p. 117. ~ bitri in closed form.
    (Contributed by NM, 3-Jan-2005.)
    """
    lb = ProofBuilder(sys, "bitr")
    s1 = lb.ref("s1", "( ( φ ↔ ψ ) → ( ( φ ↔ χ ) ↔ ( ψ ↔ χ ) ) )", ref="bibi1", note="bibi1")
    res = lb.ref("res", "( ( ( φ ↔ ψ ) ∧ ( ψ ↔ χ ) ) → ( φ ↔ χ ) )", s1, ref="biimpar", note="biimpar")
    return lb.build(res)

def prove_biantr(sys: System) -> Proof:
    """A transitive law of equivalence.  Compare Theorem *4.22 of
    [WhiteheadRussell] p. 117.  (Contributed by NM, 18-Aug-1993.)
    """
    lb = ProofBuilder(sys, "biantr")
    s1 = lb.ref("s1", "( ( χ ↔ ψ ) → ( χ ↔ ψ ) )", ref="id", note="id")
    s2 = lb.ref("s2", "( ( χ ↔ ψ ) → ( ( φ ↔ χ ) ↔ ( φ ↔ ψ ) ) )", s1, ref="bibi2d", note="bibi2d")
    res = lb.ref("res", "( ( ( φ ↔ ψ ) ∧ ( χ ↔ ψ ) ) → ( φ ↔ χ ) )", s2, ref="biimparc", note="biimparc")
    return lb.build(res)

def prove_pm4_14(sys: System) -> Proof:
    """Theorem *4.14 of [WhiteheadRussell] p. 117.  Related to ~ con34b .
    (Contributed by NM, 3-Jan-2005.)  (Proof shortened by Wolf Lammen,
    23-Oct-2012.)
    """
    lb = ProofBuilder(sys, "pm4.14")
    s1 = lb.ref("s1", "( ( ψ → χ ) ↔ ( ¬ χ → ¬ ψ ) )", ref="con34b", note="con34b")
    s2 = lb.ref("s2", "( ( φ → ( ψ → χ ) ) ↔ ( φ → ( ¬ χ → ¬ ψ ) ) )", s1, ref="imbi2i", note="imbi2i")
    s3 = lb.ref("s3", "( ( ( φ ∧ ψ ) → χ ) ↔ ( φ → ( ψ → χ ) ) )", ref="impexp", note="impexp")
    s4 = lb.ref("s4", "( ( ( φ ∧ ¬ χ ) → ¬ ψ ) ↔ ( φ → ( ¬ χ → ¬ ψ ) ) )", ref="impexp", note="impexp")
    res = lb.ref("res", "( ( ( φ ∧ ψ ) → χ ) ↔ ( ( φ ∧ ¬ χ ) → ¬ ψ ) )", s2, s3, s4, ref="3bitr4i", note="3bitr4i")
    return lb.build(res)

def prove_pm3_37(sys: System) -> Proof:
    """Theorem *3.37 (Transp) of [WhiteheadRussell] p. 112.  (Contributed by NM,
    3-Jan-2005.)  (Proof shortened by Wolf Lammen, 23-Oct-2012.)
    """
    lb = ProofBuilder(sys, "pm3.37")
    s1 = lb.ref("s1", "( ( ( φ ∧ ψ ) → χ ) ↔ ( ( φ ∧ ¬ χ ) → ¬ ψ ) )", ref="pm4.14", note="pm4.14")
    res = lb.ref("res", "( ( ( φ ∧ ψ ) → χ ) → ( ( φ ∧ ¬ χ ) → ¬ ψ ) )", s1, ref="biimpi", note="biimpi")
    return lb.build(res)

def prove_anim12(sys: System) -> Proof:
    """Conjoin antecedents and consequents of two premises.  This is the closed
    theorem form of ~ anim12d .  Theorem *3.47 of [WhiteheadRussell] p. 113.
    It was proved by Leibniz, and it evidently pleased him enough to call it
    _praeclarum theorema_ (splendid theorem).  (Contributed by NM,
    12-Aug-1993.)  (Proof shortened by Wolf Lammen, 7-Apr-2013.)
    """
    lb = ProofBuilder(sys, "anim12")
    s1 = lb.ref("s1", "( ( φ → ψ ) → ( φ → ψ ) )", ref="id", note="id")
    s2 = lb.ref("s2", "( ( χ → θ ) → ( χ → θ ) )", ref="id", note="id")
    res = lb.ref("res", "( ( ( φ → ψ ) ∧ ( χ → θ ) ) → ( ( φ ∧ χ ) → ( ψ ∧ θ ) ) )", s1, s2, ref="im2anan9", note="im2anan9")
    return lb.build(res)

def prove_pm3_4(sys: System) -> Proof:
    """Conjunction implies implication.  Theorem *3.4 of [WhiteheadRussell]
    p. 113.  (Contributed by NM, 31-Jul-1995.)
    """
    lb = ProofBuilder(sys, "pm3.4")
    s1 = lb.ref("s1", "( ( φ ∧ ψ ) → ψ )", ref="simpr", note="simpr")
    res = lb.ref("res", "( ( φ ∧ ψ ) → ( φ → ψ ) )", s1, ref="a1d", note="a1d")
    return lb.build(res)

def prove_exbiri(sys: System) -> Proof:
    """Inference form of ~ exbir .  This proof is ~ exbiriVD automatically
    translated and minimized.  (Contributed by Alan Sare, 31-Dec-2011.)
    (Proof shortened by Wolf Lammen, 27-Jan-2013.)
    """
    lb = ProofBuilder(sys, "exbiri")
    h1 = lb.hyp("exbiri.1", "( ( φ ∧ ψ ) → ( χ ↔ θ ) )")
    s1 = lb.ref("s1", "( ( ( φ ∧ ψ ) ∧ θ ) → χ )", h1, ref="biimpar", note="biimpar")
    res = lb.ref("res", "( φ → ( ψ → ( θ → χ ) ) )", s1, ref="exp31", note="exp31")
    return lb.build(res)

def prove_pm2_61ian(sys: System) -> Proof:
    """Elimination of an antecedent.  (Contributed by NM, 1-Jan-2005.)"""
    lb = ProofBuilder(sys, "pm2.61ian")
    h1 = lb.hyp("pm2.61ian.1", "( ( φ ∧ ψ ) → χ )")
    h2 = lb.hyp("pm2.61ian.2", "( ( ¬ φ ∧ ψ ) → χ )")
    s1 = lb.ref("s1", "( φ → ( ψ → χ ) )", h1, ref="ex", note="ex")
    s2 = lb.ref("s2", "( ¬ φ → ( ψ → χ ) )", h2, ref="ex", note="ex")
    res = lb.ref("res", "( ψ → χ )", s1, s2, ref="pm2.61i", note="pm2.61i")
    return lb.build(res)

def prove_pm2_61dan(sys: System) -> Proof:
    """Elimination of an antecedent.  (Contributed by NM, 1-Jan-2005.)"""
    lb = ProofBuilder(sys, "pm2.61dan")
    h1 = lb.hyp("pm2.61dan.1", "( ( φ ∧ ψ ) → χ )")
    h2 = lb.hyp("pm2.61dan.2", "( ( φ ∧ ¬ ψ ) → χ )")
    s1 = lb.ref("s1", "( φ → ( ψ → χ ) )", h1, ref="ex", note="ex")
    s2 = lb.ref("s2", "( φ → ( ¬ ψ → χ ) )", h2, ref="ex", note="ex")
    res = lb.ref("res", "( φ → χ )", s1, s2, ref="pm2.61d", note="pm2.61d")
    return lb.build(res)

def prove_pm2_61ddan(sys: System) -> Proof:
    """Elimination of two antecedents.  (Contributed by NM, 9-Jul-2013.)"""
    lb = ProofBuilder(sys, "pm2.61ddan")
    h1 = lb.hyp("pm2.61ddan.1", "( ( φ ∧ ψ ) → θ )")
    h2 = lb.hyp("pm2.61ddan.2", "( ( φ ∧ χ ) → θ )")
    h3 = lb.hyp("pm2.61ddan.3", "( ( φ ∧ ( ¬ ψ ∧ ¬ χ ) ) → θ )")
    s1 = lb.ref("s1", "( ( ( φ ∧ ¬ ψ ) ∧ χ ) → θ )", h2, ref="adantlr", note="adantlr")
    s2 = lb.ref("s2", "( ( ( φ ∧ ¬ ψ ) ∧ ¬ χ ) → θ )", h3, ref="anassrs", note="anassrs")
    s3 = lb.ref("s3", "( ( φ ∧ ¬ ψ ) → θ )", s1, s2, ref="pm2.61dan", note="pm2.61dan")
    res = lb.ref("res", "( φ → θ )", h1, s3, ref="pm2.61dan", note="pm2.61dan")
    return lb.build(res)

def prove_pm2_61dda(sys: System) -> Proof:
    """Elimination of two antecedents.  (Contributed by NM, 9-Jul-2013.)"""
    lb = ProofBuilder(sys, "pm2.61dda")
    h1 = lb.hyp("pm2.61dda.1", "( ( φ ∧ ¬ ψ ) → θ )")
    h2 = lb.hyp("pm2.61dda.2", "( ( φ ∧ ¬ χ ) → θ )")
    h3 = lb.hyp("pm2.61dda.3", "( ( φ ∧ ( ψ ∧ χ ) ) → θ )")
    s1 = lb.ref("s1", "( ( ( φ ∧ ψ ) ∧ χ ) → θ )", h3, ref="anassrs", note="anassrs")
    s2 = lb.ref("s2", "( ( ( φ ∧ ψ ) ∧ ¬ χ ) → θ )", h2, ref="adantlr", note="adantlr")
    s3 = lb.ref("s3", "( ( φ ∧ ψ ) → θ )", s1, s2, ref="pm2.61dan", note="pm2.61dan")
    res = lb.ref("res", "( φ → θ )", s3, h1, ref="pm2.61dan", note="pm2.61dan")
    return lb.build(res)

def prove_mtand(sys: System) -> Proof:
    """A modus tollens deduction.  (Contributed by Jeff Hankins,
    19-Aug-2009.)
    """
    lb = ProofBuilder(sys, "mtand")
    h1 = lb.hyp("mtand.1", "( φ → ¬ χ )")
    h2 = lb.hyp("mtand.2", "( ( φ ∧ ψ ) → χ )")
    s1 = lb.ref("s1", "( φ → ( ψ → χ ) )", h2, ref="ex", note="ex")
    res = lb.ref("res", "( φ → ¬ ψ )", h1, s1, ref="mtod", note="mtod")
    return lb.build(res)

def prove_pm2_65da(sys: System) -> Proof:
    """Deduction for proof by contradiction.  (Contributed by NM,
    12-Jun-2014.)
    """
    lb = ProofBuilder(sys, "pm2.65da")
    h1 = lb.hyp("pm2.65da.1", "( ( φ ∧ ψ ) → χ )")
    h2 = lb.hyp("pm2.65da.2", "( ( φ ∧ ψ ) → ¬ χ )")
    s1 = lb.ref("s1", "( φ → ( ψ → χ ) )", h1, ref="ex", note="ex")
    s2 = lb.ref("s2", "( φ → ( ψ → ¬ χ ) )", h2, ref="ex", note="ex")
    res = lb.ref("res", "( φ → ¬ ψ )", s1, s2, ref="pm2.65d", note="pm2.65d")
    return lb.build(res)

def prove_condan(sys: System) -> Proof:
    """Proof by contradiction.  (Contributed by NM, 9-Feb-2006.)  (Proof
    shortened by Wolf Lammen, 19-Jun-2014.)
    """
    lb = ProofBuilder(sys, "condan")
    h1 = lb.hyp("condan.1", "( ( φ ∧ ¬ ψ ) → χ )")
    h2 = lb.hyp("condan.2", "( ( φ ∧ ¬ ψ ) → ¬ χ )")
    s1 = lb.ref("s1", "( φ → ¬ ¬ ψ )", h1, h2, ref="pm2.65da", note="pm2.65da")
    res = lb.ref("res", "( φ → ψ )", s1, ref="notnotrd", note="notnotrd")
    return lb.build(res)

def prove_biadan(sys: System) -> Proof:
    """An implication is equivalent to the equivalence of some implied
    equivalence and some other equivalence involving a conjunction.  A utility
    lemma as illustrated in ~ biadanii and ~ elelb .  (Contributed by BJ,
    4-Mar-2023.)  (Proof shortened by Wolf Lammen, 8-Mar-2023.)
    """
    lb = ProofBuilder(sys, "biadan")
    s1 = lb.ref("s1", "( ( φ → ψ ) ↔ ( φ ↔ ( ψ ∧ φ ) ) )", ref="pm4.71r", note="pm4.71r")
    s2 = lb.ref("s2", "( ( φ ↔ ( ψ ∧ φ ) ) ↔ ( ( ψ ∧ φ ) ↔ φ ) )", ref="bicom", note="bicom")
    s3 = lb.ref("s3", "( ( φ ↔ ( ψ ∧ χ ) ) ↔ ( ( ψ ∧ χ ) ↔ φ ) )", ref="bicom", note="bicom")
    s4 = lb.ref("s4", "( ( ψ → ( φ ↔ χ ) ) ↔ ( ( ψ ∧ φ ) ↔ ( ψ ∧ χ ) ) )", ref="pm5.32", note="pm5.32")
    s5 = lb.ref("s5", "( ( ( φ ↔ ( ψ ∧ χ ) ) ↔ ( ψ → ( φ ↔ χ ) ) ) ↔ ( ( ( ψ ∧ χ ) ↔ φ ) ↔ ( ( ψ ∧ φ ) ↔ ( ψ ∧ χ ) ) ) )", s3, s4, ref="bibi12i", note="bibi12i")
    s6 = lb.ref("s6", "( ( ( ψ → ( φ ↔ χ ) ) ↔ ( φ ↔ ( ψ ∧ χ ) ) ) ↔ ( ( φ ↔ ( ψ ∧ χ ) ) ↔ ( ψ → ( φ ↔ χ ) ) ) )", ref="bicom", note="bicom")
    s7 = lb.ref("s7", "( ( ( ψ ∧ φ ) ↔ φ ) ↔ ( ( ( ψ ∧ χ ) ↔ φ ) ↔ ( ( ψ ∧ φ ) ↔ ( ψ ∧ χ ) ) ) )", ref="biluk", note="biluk")
    s8 = lb.ref("s8", "( ( ( ψ ∧ φ ) ↔ φ ) ↔ ( ( ψ → ( φ ↔ χ ) ) ↔ ( φ ↔ ( ψ ∧ χ ) ) ) )", s5, s6, s7, ref="3bitr4ri", note="3bitr4ri")
    res = lb.ref("res", "( ( φ → ψ ) ↔ ( ( ψ → ( φ ↔ χ ) ) ↔ ( φ ↔ ( ψ ∧ χ ) ) ) )", s1, s2, s8, ref="3bitri", note="3bitri")
    return lb.build(res)

def prove_biadani(sys: System) -> Proof:
    """Inference associated with ~ biadan .  (Contributed by BJ,
    4-Mar-2023.)
    """
    lb = ProofBuilder(sys, "biadani")
    h1 = lb.hyp("biadani.1", "( φ → ψ )")
    s1 = lb.ref("s1", "( ( φ → ψ ) ↔ ( ( ψ → ( φ ↔ χ ) ) ↔ ( φ ↔ ( ψ ∧ χ ) ) ) )", ref="biadan", note="biadan")
    res = lb.ref("res", "( ( ψ → ( φ ↔ χ ) ) ↔ ( φ ↔ ( ψ ∧ χ ) ) )", h1, s1, ref="mpbi", note="mpbi")
    return lb.build(res)

def prove_biadaniALT(sys: System) -> Proof:
    """Alternate proof of ~ biadani not using ~ biadan .  (Contributed by BJ,
    4-Mar-2023.)  (Proof modification is discouraged.)
    (New usage is discouraged.)
    """
    lb = ProofBuilder(sys, "biadaniALT")
    h1 = lb.hyp("biadani.1", "( φ → ψ )")
    s1 = lb.ref("s1", "( ( ψ → ( φ ↔ χ ) ) ↔ ( ( ψ ∧ φ ) ↔ ( ψ ∧ χ ) ) )", ref="pm5.32", note="pm5.32")
    s2 = lb.ref("s2", "( φ ↔ ( ψ ∧ φ ) )", h1, ref="pm4.71ri", note="pm4.71ri")
    s3 = lb.ref("s3", "( ( φ ↔ ( ψ ∧ χ ) ) ↔ ( ( ψ ∧ φ ) ↔ ( ψ ∧ χ ) ) )", s2, ref="bibi1i", note="bibi1i")
    res = lb.ref("res", "( ( ψ → ( φ ↔ χ ) ) ↔ ( φ ↔ ( ψ ∧ χ ) ) )", s1, s3, ref="bitr4i", note="bitr4i")
    return lb.build(res)

def prove_biadanii(sys: System) -> Proof:
    """Inference associated with ~ biadani .  Add a conjunction to an
    equivalence.  (Contributed by Jeff Madsen, 20-Jun-2011.)  (Proof
    shortened by BJ, 4-Mar-2023.)
    """
    lb = ProofBuilder(sys, "biadanii")
    h1 = lb.hyp("biadani.1", "( φ → ψ )")
    h2 = lb.hyp("biadanii.2", "( ψ → ( φ ↔ χ ) )")
    s1 = lb.ref("s1", "( ( ψ → ( φ ↔ χ ) ) ↔ ( φ ↔ ( ψ ∧ χ ) ) )", h1, ref="biadani", note="biadani")
    res = lb.ref("res", "( φ ↔ ( ψ ∧ χ ) )", h2, s1, ref="mpbi", note="mpbi")
    return lb.build(res)

def prove_biadanid(sys: System) -> Proof:
    """Deduction associated with ~ biadani .  Add a conjunction to an
    equivalence.  (Contributed by Thierry Arnoux, 16-Jun-2024.)
    """
    lb = ProofBuilder(sys, "biadanid")
    h1 = lb.hyp("biadanid.1", "( ( φ ∧ ψ ) → χ )")
    h2 = lb.hyp("biadanid.2", "( ( φ ∧ χ ) → ( ψ ↔ θ ) )")
    s1 = lb.ref("s1", "( ( ( φ ∧ χ ) ∧ ψ ) → θ )", h2, ref="biimpa", note="biimpa")
    s2 = lb.ref("s2", "( ( ( φ ∧ ψ ) ∧ χ ) → θ )", s1, ref="an32s", note="an32s")
    s3 = lb.ref("s3", "( ( φ ∧ ψ ) → θ )", h1, s2, ref="mpdan", note="mpdan")
    s4 = lb.ref("s4", "( ( φ ∧ ψ ) → ( χ ∧ θ ) )", h1, s3, ref="jca", note="jca")
    s5 = lb.ref("s5", "( ( ( φ ∧ χ ) ∧ θ ) → ψ )", h2, ref="biimpar", note="biimpar")
    s6 = lb.ref("s6", "( ( φ ∧ ( χ ∧ θ ) ) → ψ )", s5, ref="anasss", note="anasss")
    res = lb.ref("res", "( φ → ( ψ ↔ ( χ ∧ θ ) ) )", s4, s6, ref="impbida", note="impbida")
    return lb.build(res)

def prove_pm5_1(sys: System) -> Proof:
    """Two propositions are equivalent if they are both true.  Theorem *5.1 of
    [WhiteheadRussell] p. 123.  (Contributed by NM, 21-May-1994.)
    """
    lb = ProofBuilder(sys, "pm5.1")
    s1 = lb.ref("s1", "( φ → ( ψ ↔ ( φ ↔ ψ ) ) )", ref="pm5.501", note="pm5.501")
    res = lb.ref("res", "( ( φ ∧ ψ ) → ( φ ↔ ψ ) )", s1, ref="biimpa", note="biimpa")
    return lb.build(res)

def prove_pm5_21(sys: System) -> Proof:
    """Two propositions are equivalent if they are both false.  Theorem *5.21 of
    [WhiteheadRussell] p. 124.  (Contributed by NM, 21-May-1994.)
    """
    lb = ProofBuilder(sys, "pm5.21")
    s1 = lb.ref("s1", "( ¬ φ → ( ¬ ψ → ( φ ↔ ψ ) ) )", ref="pm5.21im", note="pm5.21im")
    res = lb.ref("res", "( ( ¬ φ ∧ ¬ ψ ) → ( φ ↔ ψ ) )", s1, ref="imp", note="imp")
    return lb.build(res)

def prove_pm5_35(sys: System) -> Proof:
    """Theorem *5.35 of [WhiteheadRussell] p. 125.  Closed form of ~ 2thd .
    (Contributed by NM, 3-Jan-2005.)
    """
    lb = ProofBuilder(sys, "pm5.35")
    s1 = lb.ref("s1", "( ( ( φ → ψ ) ∧ ( φ → χ ) ) → ( ( φ → ψ ) ↔ ( φ → χ ) ) )", ref="pm5.1", note="pm5.1")
    res = lb.ref("res", "( ( ( φ → ψ ) ∧ ( φ → χ ) ) → ( φ → ( ψ ↔ χ ) ) )", s1, ref="pm5.74rd", note="pm5.74rd")
    return lb.build(res)

def prove_abai(sys: System) -> Proof:
    """Introduce one conjunct as an antecedent to the other.  "abai" stands for
    "and, biconditional, and, implication".  (Contributed by NM, 12-Aug-1993.)
    (Proof shortened by Wolf Lammen, 7-Dec-2012.)
    """
    lb = ProofBuilder(sys, "abai")
    s1 = lb.ref("s1", "( φ → ( ψ ↔ ( φ → ψ ) ) )", ref="biimt", note="biimt")
    res = lb.ref("res", "( ( φ ∧ ψ ) ↔ ( φ ∧ ( φ → ψ ) ) )", s1, ref="pm5.32i", note="pm5.32i")
    return lb.build(res)

def prove_abab(sys: System) -> Proof:
    """Introduce one conjunct as equivalent to the other.  "abab" stands for
    "and, biconditional, and, biconditional".  (Contributed by Wolf Lammen,
    4-Jun-2026.)
    """
    lb = ProofBuilder(sys, "abab")
    s1 = lb.ref("s1", "( ( φ ∧ ψ ) → φ )", ref="simpl", note="simpl")
    s2 = lb.ref("s2", "( ( φ ∧ ψ ) → ( φ ↔ ψ ) )", ref="pm5.1", note="pm5.1")
    s3 = lb.ref("s3", "( ( φ ∧ ψ ) → ( φ ∧ ( φ ↔ ψ ) ) )", s1, s2, ref="jca", note="jca")
    s4 = lb.ref("s4", "( ( φ ↔ ψ ) → ( φ → ψ ) )", ref="biimp", note="biimp")
    s5 = lb.ref("s5", "( ( φ ∧ ( φ ↔ ψ ) ) → ( φ ∧ ( φ → ψ ) ) )", s4, ref="anim2i", note="anim2i")
    s6 = lb.ref("s6", "( ( φ ∧ ψ ) ↔ ( φ ∧ ( φ → ψ ) ) )", ref="abai", note="abai")
    s7 = lb.ref("s7", "( ( φ ∧ ( φ ↔ ψ ) ) → ( φ ∧ ψ ) )", s5, s6, ref="sylibr", note="sylibr")
    res = lb.ref("res", "( ( φ ∧ ψ ) ↔ ( φ ∧ ( φ ↔ ψ ) ) )", s3, s7, ref="impbii", note="impbii")
    return lb.build(res)

def prove_pm4_45im(sys: System) -> Proof:
    """Conjunction with implication.  Compare Theorem *4.45 of [WhiteheadRussell]
    p. 119.  (Contributed by NM, 17-May-1998.)
    """
    lb = ProofBuilder(sys, "pm4.45im")
    s1 = lb.ref("s1", "( φ → ( ψ → φ ) )", ref="ax-1", note="ax-1")
    res = lb.ref("res", "( φ ↔ ( φ ∧ ( ψ → φ ) ) )", s1, ref="pm4.71i", note="pm4.71i")
    return lb.build(res)

def prove_impimprbi(sys: System) -> Proof:
    """An implication and its reverse are equivalent exactly when both operands
    are equivalent.  The right hand side resembles that of ~ dfbi2 , but
    ` <-> ` is a weaker operator than ` /\\ ` .  Note that an implication and
    its reverse can never be simultaneously false, because of ~ pm2.521 .
    (Contributed by Wolf Lammen, 18-Dec-2023.)
    """
    lb = ProofBuilder(sys, "impimprbi")
    s1 = lb.ref("s1", "( ( φ ↔ ψ ) ↔ ( ( φ → ψ ) ∧ ( ψ → φ ) ) )", ref="dfbi2", note="dfbi2")
    s2 = lb.ref("s2", "( ( ( φ → ψ ) ∧ ( ψ → φ ) ) → ( ( φ → ψ ) ↔ ( ψ → φ ) ) )", ref="pm5.1", note="pm5.1")
    s3 = lb.ref("s3", "( ( φ ↔ ψ ) → ( ( φ → ψ ) ↔ ( ψ → φ ) ) )", s1, s2, ref="sylbi", note="sylbi")
    s4 = lb.ref("s4", "( ( φ → ψ ) → ( ( ψ → φ ) → ( φ ↔ ψ ) ) )", ref="impbi", note="impbi")
    s5 = lb.ref("s5", "( ¬ ( φ → ψ ) → ( ψ → φ ) )", ref="pm2.521", note="pm2.521")
    s6 = lb.ref("s6", "( ¬ ( φ → ψ ) → ( ¬ ( ψ → φ ) → ( φ ↔ ψ ) ) )", s5, ref="pm2.24d", note="pm2.24d")
    s7 = lb.ref("s7", "( ( ( φ → ψ ) ↔ ( ψ → φ ) ) → ( φ ↔ ψ ) )", s4, s6, ref="bija", note="bija")
    res = lb.ref("res", "( ( φ ↔ ψ ) ↔ ( ( φ → ψ ) ↔ ( ψ → φ ) ) )", s3, s7, ref="impbii", note="impbii")
    return lb.build(res)

def prove_nan(sys: System) -> Proof:
    """Theorem to move a conjunct in and out of a negation.  (Contributed by NM,
    9-Nov-2003.)
    """
    lb = ProofBuilder(sys, "nan")
    s1 = lb.ref("s1", "( ( ( φ ∧ ψ ) → ¬ χ ) ↔ ( φ → ( ψ → ¬ χ ) ) )", ref="impexp", note="impexp")
    s2 = lb.ref("s2", "( ( ψ → ¬ χ ) ↔ ¬ ( ψ ∧ χ ) )", ref="imnan", note="imnan")
    s3 = lb.ref("s3", "( ( φ → ( ψ → ¬ χ ) ) ↔ ( φ → ¬ ( ψ ∧ χ ) ) )", s2, ref="imbi2i", note="imbi2i")
    res = lb.ref("res", "( ( φ → ¬ ( ψ ∧ χ ) ) ↔ ( ( φ ∧ ψ ) → ¬ χ ) )", s1, s3, ref="bitr2i", note="bitr2i")
    return lb.build(res)

def prove_pm5_31(sys: System) -> Proof:
    """Theorem *5.31 of [WhiteheadRussell] p. 125.  (Contributed by NM,
    3-Jan-2005.)
    """
    lb = ProofBuilder(sys, "pm5.31")
    s1 = lb.ref("s1", "( ( χ ∧ ( φ → ψ ) ) → ( φ → ψ ) )", ref="simpr", note="simpr")
    s2 = lb.ref("s2", "( ( χ ∧ ( φ → ψ ) ) → χ )", ref="simpl", note="simpl")
    res = lb.ref("res", "( ( χ ∧ ( φ → ψ ) ) → ( φ → ( ψ ∧ χ ) ) )", s1, s2, ref="jctird", note="jctird")
    return lb.build(res)

def prove_pm5_31r(sys: System) -> Proof:
    """Variant of ~ pm5.31 .  (Contributed by Rodolfo Medina, 15-Oct-2010.)"""
    lb = ProofBuilder(sys, "pm5.31r")
