def prove_annotanannot(sys: System) -> Proof:
    """A conjunction with a negated conjunction.  (Contributed by AV,
    8-Mar-2022.)  (Proof shortened by Wolf Lammen, 1-Apr-2022.)
    """
    lb = ProofBuilder(sys, "annotanannot")
    s1 = lb.ref("s1", "( φ → ( ψ ↔ ( φ ∧ ψ ) ) )", ref="ibar", note="ibar")
    s2 = lb.ref("s2", "( φ → ( ( φ ∧ ψ ) ↔ ψ ) )", s1, ref="bicomd", note="bicomd")
    s3 = lb.ref("s3", "( φ → ( ¬ ( φ ∧ ψ ) ↔ ¬ ψ ) )", s2, ref="notbid", note="notbid")
    res = lb.ref("res", "( ( φ ∧ ¬ ( φ ∧ ψ ) ) ↔ ( φ ∧ ¬ ψ ) )", s3, ref="pm5.32i", note="pm5.32i")
    return lb.build(res)

def prove_pm5_33(sys: System) -> Proof:
    """Theorem *5.33 of [WhiteheadRussell] p. 125.  (Contributed by NM,
    3-Jan-2005.)
    """
    lb = ProofBuilder(sys, "pm5.33")
    s1 = lb.ref("s1", "( φ → ( ψ ↔ ( φ ∧ ψ ) ) )", ref="ibar", note="ibar")
    s2 = lb.ref("s2", "( φ → ( ( ψ → χ ) ↔ ( ( φ ∧ ψ ) → χ ) ) )", s1, ref="imbi1d", note="imbi1d")
    res = lb.ref("res", "( ( φ ∧ ( ψ → χ ) ) ↔ ( φ ∧ ( ( φ ∧ ψ ) → χ ) ) )", s2, ref="pm5.32i", note="pm5.32i")
    return lb.build(res)

def prove_syl12anc(sys: System) -> Proof:
    """Syllogism combined with contraction.  (Contributed by Jeff Hankins,
    1-Aug-2009.)
    """
    lb = ProofBuilder(sys, "syl12anc")
    h1 = lb.hyp("syl12anc.1", "( φ → ψ )")
    h2 = lb.hyp("syl12anc.2", "( φ → χ )")
    h3 = lb.hyp("syl12anc.3", "( φ → θ )")
    h4 = lb.hyp("syl12anc.4", "( ( ψ ∧ ( χ ∧ θ ) ) → τ )")
    s1 = lb.ref("s1", "( φ → ( χ ∧ θ ) )", h2, h3, ref="jca", note="jca")
    res = lb.ref("res", "( φ → τ )", h1, s1, h4, ref="syl2anc", note="syl2anc")
    return lb.build(res)

def prove_syl21anc(sys: System) -> Proof:
    """Syllogism combined with contraction.  (Contributed by Jeff Hankins,
    1-Aug-2009.)
    """
    lb = ProofBuilder(sys, "syl21anc")
    h1 = lb.hyp("syl12anc.1", "( φ → ψ )")
    h2 = lb.hyp("syl12anc.2", "( φ → χ )")
    h3 = lb.hyp("syl12anc.3", "( φ → θ )")
    h4 = lb.hyp("syl21anc.4", "( ( ( ψ ∧ χ ) ∧ θ ) → τ )")
    s1 = lb.ref("s1", "( φ → ( ψ ∧ χ ) )", h1, h2, ref="jca", note="jca")
    res = lb.ref("res", "( φ → τ )", s1, h3, h4, ref="syl2anc", note="syl2anc")
    return lb.build(res)

def prove_syl22anc(sys: System) -> Proof:
    """Syllogism combined with contraction.  (Contributed by NM,
    11-Mar-2012.)
    """
    lb = ProofBuilder(sys, "syl22anc")
    h1 = lb.hyp("syl12anc.1", "( φ → ψ )")
    h2 = lb.hyp("syl12anc.2", "( φ → χ )")
    h3 = lb.hyp("syl12anc.3", "( φ → θ )")
    h4 = lb.hyp("syl22anc.4", "( φ → τ )")
    h5 = lb.hyp("syl22anc.5", "( ( ( ψ ∧ χ ) ∧ ( θ ∧ τ ) ) → η )")
    s1 = lb.ref("s1", "( φ → ( ψ ∧ χ ) )", h1, h2, ref="jca", note="jca")
    res = lb.ref("res", "( φ → η )", s1, h3, h4, h5, ref="syl12anc", note="syl12anc")
    return lb.build(res)

def prove_bibiad(sys: System) -> Proof:
    """Eliminate an hypothesis ` th ` in a biconditional.  (Contributed by
    Thierry Arnoux, 4-May-2025.)
    """
    lb = ProofBuilder(sys, "bibiad")
    h1 = lb.hyp("bibiad.1", "( ( φ ∧ ψ ) → θ )")
    h2 = lb.hyp("bibiad.2", "( ( φ ∧ χ ) → θ )")
    h3 = lb.hyp("bibiad.3", "( ( φ ∧ θ ) → ( ψ ↔ χ ) )")
    s1 = lb.ref("s1", "( ( φ ∧ ψ ) → φ )", ref="simpl", note="simpl")
    s2 = lb.ref("s2", "( ( φ ∧ ψ ) → ψ )", ref="simpr", note="simpr")
    s3 = lb.ref("s3", "( ( ( φ ∧ θ ) ∧ ψ ) → χ )", h3, ref="biimpa", note="biimpa")
    s4 = lb.ref("s4", "( ( φ ∧ ψ ) → χ )", s1, h1, s2, s3, ref="syl21anc", note="syl21anc")
    s5 = lb.ref("s5", "( ( φ ∧ χ ) → φ )", ref="simpl", note="simpl")
    s6 = lb.ref("s6", "( ( φ ∧ χ ) → χ )", ref="simpr", note="simpr")
    s7 = lb.ref("s7", "( ( ( φ ∧ θ ) ∧ χ ) → ψ )", h3, ref="biimpar", note="biimpar")
    s8 = lb.ref("s8", "( ( φ ∧ χ ) → ψ )", s5, h2, s6, s7, ref="syl21anc", note="syl21anc")
    res = lb.ref("res", "( φ → ( ψ ↔ χ ) )", s4, s8, ref="impbida", note="impbida")
    return lb.build(res)

def prove_syl1111anc(sys: System) -> Proof:
    """Four-hypothesis elimination deduction for an assertion with a singleton
    virtual hypothesis collection.  Similar to ~ syl112anc except the
    unification theorem uses left-nested conjunction.  (Contributed by Alan
    Sare, 17-Oct-2017.)
    """
    lb = ProofBuilder(sys, "syl1111anc")
    h1 = lb.hyp("syl1111anc.1", "( φ → ψ )")
    h2 = lb.hyp("syl1111anc.2", "( φ → χ )")
    h3 = lb.hyp("syl1111anc.3", "( φ → θ )")
    h4 = lb.hyp("syl1111anc.4", "( φ → τ )")
    h5 = lb.hyp("syl1111anc.5", "( ( ( ( ψ ∧ χ ) ∧ θ ) ∧ τ ) → η )")
    s1 = lb.ref("s1", "( φ → ( ψ ∧ χ ) )", h1, h2, ref="jca", note="jca")
    res = lb.ref("res", "( φ → η )", s1, h3, h4, h5, ref="syl21anc", note="syl21anc")
    return lb.build(res)

def prove_syldbl2(sys: System) -> Proof:
    """Stacked hypotheseis implies goal.  (Contributed by Stanislas Polu,
    9-Mar-2020.)
    """
    lb = ProofBuilder(sys, "syldbl2")
    h1 = lb.hyp("syldbl2.1", "( ( φ ∧ ψ ) → ( ψ → θ ) )")
    s1 = lb.ref("s1", "( ψ → ( ( φ ∧ ψ ) → θ ) )", h1, ref="com12", note="com12")
    res = lb.ref("res", "( ( φ ∧ ψ ) → θ )", s1, ref="anabsi7", note="anabsi7")
    return lb.build(res)

def prove_mpsyl4anc(sys: System) -> Proof:
    """An elimination deduction.  (Contributed by Alan Sare, 17-Oct-2017.)"""
    lb = ProofBuilder(sys, "mpsyl4anc")
    h1 = lb.hyp("mpsyl4anc.1", "φ")
    h2 = lb.hyp("mpsyl4anc.2", "ψ")
    h3 = lb.hyp("mpsyl4anc.3", "χ")
    h4 = lb.hyp("mpsyl4anc.4", "( θ → τ )")
    h5 = lb.hyp("mpsyl4anc.5", "( ( ( ( φ ∧ ψ ) ∧ χ ) ∧ τ ) → η )")
    s1 = lb.ref("s1", "( θ → φ )", h1, ref="a1i", note="a1i")
    s2 = lb.ref("s2", "( θ → ψ )", h2, ref="a1i", note="a1i")
    s3 = lb.ref("s3", "( θ → χ )", h3, ref="a1i", note="a1i")
    res = lb.ref("res", "( θ → η )", s1, s2, s3, h4, h5, ref="syl1111anc", note="syl1111anc")
    return lb.build(res)

def prove_pm4_87(sys: System) -> Proof:
    """Theorem *4.87 of [WhiteheadRussell] p. 122.  (Contributed by NM,
    3-Jan-2005.)  (Proof shortened by Eric Schmidt, 26-Oct-2006.)
    """
    lb = ProofBuilder(sys, "pm4.87")
    s1 = lb.ref("s1", "( ( ( φ ∧ ψ ) → χ ) ↔ ( φ → ( ψ → χ ) ) )", ref="impexp", note="impexp")
    s2 = lb.ref("s2", "( ( φ → ( ψ → χ ) ) ↔ ( ψ → ( φ → χ ) ) )", ref="bi2.04", note="bi2.04")
    s3 = lb.ref("s3", "( ( ( ( φ ∧ ψ ) → χ ) ↔ ( φ → ( ψ → χ ) ) ) ∧ ( ( φ → ( ψ → χ ) ) ↔ ( ψ → ( φ → χ ) ) ) )", s1, s2, ref="pm3.2i", note="pm3.2i")
    s4 = lb.ref("s4", "( ( ( ψ ∧ φ ) → χ ) ↔ ( ψ → ( φ → χ ) ) )", ref="impexp", note="impexp")
    s5 = lb.ref("s5", "( ( ψ → ( φ → χ ) ) ↔ ( ( ψ ∧ φ ) → χ ) )", s4, ref="bicomi", note="bicomi")
    res = lb.ref("res", "( ( ( ( ( φ ∧ ψ ) → χ ) ↔ ( φ → ( ψ → χ ) ) ) ∧ ( ( φ → ( ψ → χ ) ) ↔ ( ψ → ( φ → χ ) ) ) ) ∧ ( ( ψ → ( φ → χ ) ) ↔ ( ( ψ ∧ φ ) → χ ) ) )", s3, s5, ref="pm3.2i", note="pm3.2i")
    return lb.build(res)

def prove_bimsc1(sys: System) -> Proof:
    """Removal of conjunct from one side of an equivalence.  (Contributed by NM,
    21-Jun-1993.)
    """
    lb = ProofBuilder(sys, "bimsc1")
    s1 = lb.ref("s1", "( ( χ ↔ ( ψ ∧ φ ) ) → ( χ ↔ ( ψ ∧ φ ) ) )", ref="id", note="id")
    s2 = lb.ref("s2", "( ( ψ ∧ φ ) → φ )", ref="simpr", note="simpr")
    s3 = lb.ref("s3", "( ( φ → ψ ) → ( φ → ( ψ ∧ φ ) ) )", ref="ancr", note="ancr")
    s4 = lb.ref("s4", "( ( φ → ψ ) → ( ( ψ ∧ φ ) ↔ φ ) )", s2, s3, ref="impbid2", note="impbid2")
    res = lb.ref("res", "( ( ( φ → ψ ) ∧ ( χ ↔ ( ψ ∧ φ ) ) ) → ( χ ↔ φ ) )", s1, s4, ref="sylan9bbr", note="sylan9bbr")
    return lb.build(res)

def prove_a2and(sys: System) -> Proof:
    """Deduction distributing a conjunction as embedded antecedent.
    (Contributed by AV, 25-Oct-2019.)  (Proof shortened by Wolf Lammen,
    19-Jan-2020.)
    """
    lb = ProofBuilder(sys, "a2and")
    h1 = lb.hyp("a2and.1", "( φ → ( ( ψ ∧ ρ ) → ( τ → θ ) ) )")
    h2 = lb.hyp("a2and.2", "( φ → ( ( ψ ∧ ρ ) → χ ) )")
    s1 = lb.ref("s1", "( φ → ( ψ → ( ρ → χ ) ) )", h2, ref="expd", note="expd")
    s2 = lb.ref("s2", "( φ → ( ( ψ ∧ ρ ) → ( ψ ∧ χ ) ) )", s1, ref="imdistand", note="imdistand")
    s3 = lb.ref("s3", "( ( ( ψ ∧ χ ) → τ ) → ( ( τ → θ ) → ( ( ψ ∧ χ ) → θ ) ) )", ref="imim1", note="imim1")
    s4 = lb.ref("s4", "( ( τ → θ ) → ( ( ψ ∧ χ ) → ( ( ( ψ ∧ χ ) → τ ) → θ ) ) )", s3, ref="com3l", note="com3l")
    s5 = lb.ref("s5", "( φ → ( ( ψ ∧ ρ ) → ( ( ( ψ ∧ χ ) → τ ) → θ ) ) )", h1, s2, s4, ref="syl6c", note="syl6c")
    res = lb.ref("res", "( φ → ( ( ( ψ ∧ χ ) → τ ) → ( ( ψ ∧ ρ ) → θ ) ) )", s5, ref="com23", note="com23")
    return lb.build(res)

def prove_animpimp2impd(sys: System) -> Proof:
    """Deduction deriving nested implications from conjunctions.  (Contributed
    by AV, 21-Aug-2022.)
    """
    lb = ProofBuilder(sys, "animpimp2impd")
    h1 = lb.hyp("animpimp2impd.1", "( ( ψ ∧ φ ) → ( χ → ( θ → η ) ) )")
    h2 = lb.hyp("animpimp2impd.2", "( ( ψ ∧ ( φ ∧ θ ) ) → ( η → τ ) )")
    s1 = lb.ref("s1", "( ( ψ ∧ φ ) → ( θ → ( η → τ ) ) )", h2, ref="expr", note="expr")
    s2 = lb.ref("s2", "( ( ψ ∧ φ ) → ( ( θ → η ) → ( θ → τ ) ) )", s1, ref="a2d", note="a2d")
    s3 = lb.ref("s3", "( ( ψ ∧ φ ) → ( χ → ( θ → τ ) ) )", h1, s2, ref="syld", note="syld")
    s4 = lb.ref("s4", "( φ → ( ψ → ( χ → ( θ → τ ) ) ) )", s3, ref="expcom", note="expcom")
    res = lb.ref("res", "( φ → ( ( ψ → χ ) → ( ψ → ( θ → τ ) ) ) )", s4, ref="a2d", note="a2d")
    return lb.build(res)


